/* ===== BHT v6.5 — \u05EA\u05DC"\u05D0 (Individual Learning Plan) ===== */
Object.assign(Pages, {

  /* ---- \u05EA\u05DC"\u05D0\u05D5\u05EA table page ---- */
  tala() {
    return `
    <div class="page-header d-flex justify-content-between align-items-start flex-wrap gap-2">
      <div><h1><i class="bi bi-file-earmark-person me-2"></i>\u05EA\u05DC"\u05D0\u05D5\u05EA - \u05EA\u05D5\u05DB\u05E0\u05D9\u05D5\u05EA \u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA \u05D0\u05D9\u05E9\u05D9\u05D5\u05EA</h1>
        <small class="text-muted">\u05E1\u05E7\u05D9\u05E8\u05EA \u05DE\u05E6\u05D1 \u05EA\u05DC"\u05D0\u05D5\u05EA \u05DC\u05DB\u05DC \u05D4\u05EA\u05DC\u05DE\u05D9\u05D3\u05D9\u05DD</small>
      </div>
      <div class="d-flex gap-2">
        <button class="btn btn-outline-success btn-sm" onclick="Pages._talaExportAll()"><i class="bi bi-printer me-1"></i>\u05D4\u05D3\u05E4\u05E1 \u05D4\u05DB\u05DC</button>
      </div>
    </div>

    <!-- Stats -->
    <div class="row g-3 mb-3">
      <div class="col-6 col-md-3"><div class="card p-3 text-center"><div class="fs-3 fw-bold text-primary" id="tala-stat-total">0</div><small class="text-muted">\u05E1\u05D4"\u05DB \u05EA\u05DC\u05DE\u05D9\u05D3\u05D9\u05DD</small></div></div>
      <div class="col-6 col-md-3"><div class="card p-3 text-center"><div class="fs-3 fw-bold text-success" id="tala-stat-has">0</div><small class="text-muted">\u05D9\u05E9 \u05EA\u05DC"\u05D0</small></div></div>
      <div class="col-6 col-md-3"><div class="card p-3 text-center"><div class="fs-3 fw-bold text-danger" id="tala-stat-missing">0</div><small class="text-muted">\u05D7\u05E1\u05E8 \u05EA\u05DC"\u05D0</small></div></div>
      <div class="col-6 col-md-3"><div class="card p-3 text-center"><div class="fs-3 fw-bold text-info" id="tala-stat-pct">0%</div><small class="text-muted">\u05D0\u05D7\u05D5\u05D6 \u05DB\u05D9\u05E1\u05D5\u05D9</small></div></div>
    </div>

    <!-- Filter -->
    <div class="d-flex gap-2 mb-3 flex-wrap">
      <input type="text" class="form-control form-control-sm" id="tala-search" placeholder="\u05D7\u05D9\u05E4\u05D5\u05E9 \u05EA\u05DC\u05DE\u05D9\u05D3..." style="max-width:250px" oninput="Pages._talaFilterTable()">
      <select class="form-select form-select-sm" id="tala-filter-status" style="width:160px" onchange="Pages._talaFilterTable()">
        <option value="">\u05DB\u05DC \u05D4\u05E1\u05D8\u05D8\u05D5\u05E1\u05D9\u05DD</option>
        <option value="has">\u05D9\u05E9 \u05EA\u05DC"\u05D0</option>
        <option value="missing">\u05D7\u05E1\u05E8 \u05EA\u05DC"\u05D0</option>
      </select>
    </div>

    <!-- Table -->
    <div class="card">
      <div class="table-responsive">
        <table class="table table-hover mb-0" id="tala-table">
          <thead class="table-light">
            <tr>
              <th>#</th>
              <th>\u05E9\u05DD \u05EA\u05DC\u05DE\u05D9\u05D3</th>
              <th>\u05DB\u05D9\u05EA\u05D4</th>
              <th>\u05E1\u05D8\u05D8\u05D5\u05E1 \u05EA\u05DC"\u05D0</th>
              <th>\u05E2\u05D3\u05DB\u05D5\u05DF \u05D0\u05D7\u05E8\u05D5\u05DF</th>
              <th>\u05DE\u05D5\u05E8\u05D4</th>
              <th>\u05E4\u05E2\u05D5\u05DC\u05D5\u05EA</th>
            </tr>
          </thead>
          <tbody id="tala-table-body"></tbody>
        </table>
      </div>
    </div>`;
  },

  talaInit() {
    const _gc = (s) => (typeof DATA_CACHE !== 'undefined' && DATA_CACHE[s]) ? DATA_CACHE[s] : [];
    let students = _gc('\u05EA\u05DC\u05DE\u05D9\u05D3\u05D9\u05DD');
    if (!students.length) students = Pages._studentsDemoData ? Pages._studentsDemoData() : [];

    let hasCount = 0;
    const rows = students.map((s, i) => {
      const sId = String(Utils.rowId(s) || s._row || i);
      const name = Utils.fullName(s);
      const cls = s['\u05DB\u05D9\u05EA\u05D4'] || '--';
      const key = 'bht_tala_' + sId;
      const data = localStorage.getItem(key);
      let hasTala = false;
      let lastUpdate = '--';
      let teacher = '--';
      if (data) {
        try {
          const parsed = JSON.parse(data);
          hasTala = true;
          hasCount++;
          lastUpdate = parsed._lastUpdate || '--';
          teacher = parsed['\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0'] || '--';
        } catch(e) { /* silent */ }
      }
      return { sId, name, cls, hasTala, lastUpdate, teacher };
    });

    const total = students.length;
    const missing = total - hasCount;
    const el = (id) => document.getElementById(id);
    if (el('tala-stat-total')) el('tala-stat-total').textContent = total;
    if (el('tala-stat-has')) el('tala-stat-has').textContent = hasCount;
    if (el('tala-stat-missing')) el('tala-stat-missing').textContent = missing;
    if (el('tala-stat-pct')) el('tala-stat-pct').textContent = total ? Math.round(hasCount / total * 100) + '%' : '0%';

    Pages._talaRows = rows;
    Pages._talaRenderTable(rows);
  },

  _talaRenderTable(rows) {
    const tbody = document.getElementById('tala-table-body');
    if (!tbody) return;
    tbody.innerHTML = rows.map((r, i) => `
      <tr data-name="${r.name}" data-status="${r.hasTala ? 'has' : 'missing'}">
        <td>${i + 1}</td>
        <td><a href="#students/${r.sId}" class="fw-bold text-decoration-none">${r.name}</a></td>
        <td>${r.cls}</td>
        <td>${r.hasTala
          ? '<span class="badge bg-success"><i class="bi bi-check-circle me-1"></i>\u05E7\u05D9\u05D9\u05DD</span>'
          : '<span class="badge bg-danger"><i class="bi bi-x-circle me-1"></i>\u05D7\u05E1\u05E8</span>'}</td>
        <td><small class="text-muted">${r.lastUpdate}</small></td>
        <td><small>${r.teacher}</small></td>
        <td>
          <div class="d-flex gap-1">
            <a href="#students/${r.sId}" class="btn btn-outline-primary btn-sm" title="\u05E2\u05E8\u05D9\u05DB\u05D4" onclick="setTimeout(()=>Pages._talaActivateTab(),500)"><i class="bi bi-pencil"></i></a>
            ${r.hasTala ? `<button class="btn btn-outline-success btn-sm" title="\u05D4\u05D3\u05E4\u05E1\u05D4" onclick="Pages._talaPrint('${r.sId}')"><i class="bi bi-printer"></i></button>` : ''}
          </div>
        </td>
      </tr>
    `).join('');
  },

  _talaFilterTable() {
    const search = (document.getElementById('tala-search')?.value || '').trim().toLowerCase();
    const statusFilter = document.getElementById('tala-filter-status')?.value || '';
    const rows = (Pages._talaRows || []).filter(r => {
      if (search && !r.name.toLowerCase().includes(search)) return false;
      if (statusFilter === 'has' && !r.hasTala) return false;
      if (statusFilter === 'missing' && r.hasTala) return false;
      return true;
    });
    Pages._talaRenderTable(rows);
  },

  _talaActivateTab() {
    const tab = document.querySelector('a[href="#tab-tala"]');
    if (tab) tab.click();
  },

  /* ---- Student card tab content ---- */
  _talaFields: [
    { key: '\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA', label: '\u05E8\u05E7\u05E2 \u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA', icon: 'bi-file-medical' },
    { key: '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7', label: '\u05EA\u05D7\u05D5\u05DE\u05D9 \u05DB\u05D5\u05D7 (\u05DE\u05D5\u05E7\u05D3\u05D9 \u05DB\u05D5\u05D7)', icon: 'bi-star' },
    { key: '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7', label: '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD \u05DC\u05D7\u05D9\u05D6\u05D5\u05E7 (\u05DE\u05D5\u05E7\u05D3\u05D9\u05DD \u05DC\u05D7\u05D9\u05D6\u05D5\u05E7)', icon: 'bi-lightning' },
    { key: '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD', label: '\u05D9\u05E2\u05D3\u05D9\u05DD \u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD', icon: 'bi-mortarboard' },
    { key: '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD', label: '\u05D9\u05E2\u05D3\u05D9\u05DD \u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD', icon: 'bi-people' },
    { key: '\u05D4\u05EA\u05D0\u05DE\u05D5\u05EA', label: '\u05D4\u05EA\u05D0\u05DE\u05D5\u05EA', icon: 'bi-sliders' },
    { key: '\u05D4\u05E0\u05D7\u05D9\u05D5\u05EA', label: '\u05D4\u05E0\u05D7\u05D9\u05D5\u05EA', icon: 'bi-list-check' },
    { key: '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA', label: '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA \u05D4\u05D5\u05E8\u05D0\u05D4 \u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA', icon: 'bi-lightbulb' },
    { key: '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA', label: '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA \u05D4\u05D5\u05E8\u05D0\u05D4 \u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA', icon: 'bi-chat-heart' },
    { key: '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0', label: '\u05E9\u05DD \u05DE\u05D5\u05E8\u05D4 \u05D4\u05EA\u05DC"\u05D0', icon: 'bi-person-badge' }
  ],

  _talaRenderTab(sId, studentName) {
    const key = 'bht_tala_' + sId;
    let data = {};
    try { data = (() => { try { return JSON.parse(localStorage.getItem(key) || '{}'); } catch(e) { return {} === '{}' ? {} : []; } })(); } catch(e) { /* silent */ }

    const fieldsHTML = Pages._talaFields.map(f => {
      const val = data[f.key] || '';
      const isTeacher = f.key === '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0';
      return `
        <div class="col-12 ${isTeacher ? 'col-md-6' : ''}">
          <div class="card border-0 shadow-sm mb-2">
            <div class="card-body p-3">
              <label class="form-label fw-bold text-primary mb-1"><i class="bi ${f.icon} me-1"></i>${f.label}</label>
              ${isTeacher
                ? `<input type="text" class="form-control" id="tala-field-${f.key}" value="${(val || '').replace(/"/g, '&quot;')}" placeholder="\u05D4\u05D6\u05DF \u05E9\u05DD \u05DE\u05D5\u05E8\u05D4...">`
                : `<textarea class="form-control" id="tala-field-${f.key}" rows="3" placeholder="\u05D4\u05D6\u05DF \u05EA\u05D5\u05DB\u05DF...">${val}</textarea>`
              }
            </div>
          </div>
        </div>`;
    }).join('');

    return `
      <div class="card p-3">
        <div class="d-flex justify-content-between align-items-center mb-3">
          <h6 class="fw-bold mb-0"><i class="bi bi-file-earmark-person me-2"></i>\u05EA\u05D5\u05DB\u05E0\u05D9\u05EA \u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05EA \u05D0\u05D9\u05E9\u05D9\u05EA (\u05EA\u05DC"\u05D0)</h6>
          <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" onclick="Pages._talaSave('${sId}')"><i class="bi bi-save me-1"></i>\u05E9\u05DE\u05D9\u05E8\u05D4</button>
            <button class="btn btn-outline-success btn-sm" onclick="Pages._talaPrint('${sId}')"><i class="bi bi-printer me-1"></i>\u05D4\u05D3\u05E4\u05E1\u05D4</button>
          </div>
        </div>
        ${data._lastUpdate ? `<div class="alert alert-info py-2 small mb-3"><i class="bi bi-clock me-1"></i>\u05E2\u05D3\u05DB\u05D5\u05DF \u05D0\u05D7\u05E8\u05D5\u05DF: ${data._lastUpdate}</div>` : ''}
        <div class="row g-2">
          ${fieldsHTML}
        </div>
        <div class="mt-3 text-center">
          <button class="btn btn-primary" onclick="Pages._talaSave('${sId}')"><i class="bi bi-save me-1"></i>\u05E9\u05DE\u05D5\u05E8 \u05EA\u05DC"\u05D0</button>
          <button class="btn btn-outline-success ms-2" onclick="Pages._talaPrint('${sId}')"><i class="bi bi-printer me-1"></i>\u05D4\u05D3\u05E4\u05E1 \u05DC-PDF</button>
          <button class="btn btn-outline-danger ms-2" onclick="Pages._talaClear('${sId}')"><i class="bi bi-trash me-1"></i>\u05E0\u05E7\u05D4 \u05D4\u05DB\u05DC</button>
        </div>
      </div>`;
  },

  _talaSave(sId) {
    const data = {};
    Pages._talaFields.forEach(f => {
      const el = document.getElementById('tala-field-' + f.key);
      if (el) data[f.key] = el.value.trim();
    });
    data._lastUpdate = new Date().toLocaleDateString('he-IL') + ' ' + new Date().toLocaleTimeString('he-IL', { hour: '2-digit', minute: '2-digit' });
    data._studentName = Pages._scStudentName || '';
    localStorage.setItem('bht_tala_' + sId, JSON.stringify(data));
    if (typeof Utils !== 'undefined' && Utils.toast) {
      Utils.toast('\u05EA\u05DC"\u05D0 \u05E0\u05E9\u05DE\u05E8\u05D4 \u05D1\u05D4\u05E6\u05DC\u05D7\u05D4!', 'success');
    }
  },

  async _talaClear(sId) {
    if (!await Utils.confirm('\u05DE\u05D7\u05D9\u05E7\u05EA \u05EA\u05DC"\u05D0', '\u05DC\u05DE\u05D7\u05D5\u05E7 \u05D0\u05EA \u05DB\u05DC \u05E0\u05EA\u05D5\u05E0\u05D9 \u05D4\u05EA\u05DC"\u05D0 \u05E9\u05DC \u05EA\u05DC\u05DE\u05D9\u05D3 \u05D6\u05D4?')) return;
    localStorage.removeItem('bht_tala_' + sId);
    // Re-render the tab
    const container = document.getElementById('tab-tala');
    if (container) {
      container.innerHTML = Pages._talaRenderTab(sId, Pages._scStudentName || '');
    }
    if (typeof Utils !== 'undefined' && Utils.toast) {
      Utils.toast('\u05EA\u05DC"\u05D0 \u05E0\u05DE\u05D7\u05E7\u05D4', 'warning');
    }
  },

  _talaPrint(sId) {
    const key = 'bht_tala_' + sId;
    let data = {};
    try { data = (() => { try { return JSON.parse(localStorage.getItem(key) || '{}'); } catch(e) { return {} === '{}' ? {} : []; } })(); } catch(e) { /* silent */ }
    const studentName = data._studentName || Pages._scStudentName || '\u05EA\u05DC\u05DE\u05D9\u05D3';

    const fields = Pages._talaFields;
    const fieldsHTML = fields.map(f => {
      const val = data[f.key] || '\u05DC\u05D0 \u05E6\u05D5\u05D9\u05DF';
      const isTeacher = f.key === '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0';
      return `
        <div style="margin-bottom:12px;page-break-inside:avoid">
          <div style="font-weight:bold;color:#1a73e8;margin-bottom:4px;font-size:14px">${f.label}</div>
          <div style="padding:8px 12px;background:#f8f9fa;border-radius:6px;border-right:3px solid #1a73e8;min-height:${isTeacher ? '36px' : '60px'};white-space:pre-wrap;font-size:13px">${val}</div>
        </div>`;
    }).join('');

    const printHTML = `<!DOCTYPE html>
<html dir="rtl" lang="he">
<head>
  <meta charset="UTF-8">
  <title>\u05EA\u05DC"\u05D0 - ${studentName}</title>
  <link href="https://fonts.googleapis.com/css2?family=Heebo:wght@300;400;500;700&display=swap" rel="stylesheet">
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: 'Heebo', sans-serif; direction: rtl; padding: 30px; color: #333; }
    .header { text-align: center; margin-bottom: 30px; padding-bottom: 20px; border-bottom: 2px solid #1a73e8; }
    .header h1 { font-size: 22px; color: #1a73e8; margin-bottom: 4px; }
    .header h2 { font-size: 18px; color: #333; }
    .header .subtitle { font-size: 13px; color: #666; margin-top: 4px; }
    .student-name { font-size: 20px; font-weight: 700; text-align: center; margin-bottom: 20px; padding: 12px; background: #e8f0fe; border-radius: 8px; }
    @media print {
      body { padding: 15px; }
      @page { margin: 1.5cm; }
    }
  </style>
</head>
<body>
  <div class="header">
    <h1>\u05D1\u05D9\u05EA \u05D4\u05EA\u05DC\u05DE\u05D5\u05D3</h1>
    <h2>\u05EA\u05D5\u05DB\u05E0\u05D9\u05EA \u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05EA \u05D0\u05D9\u05E9\u05D9\u05EA (\u05EA\u05DC"\u05D0)</h2>
    <div class="subtitle">\u05E9\u05E0\u05EA \u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05DD \u05EA\u05E9\u05E4"\u05D5 | ${data._lastUpdate || new Date().toLocaleDateString('he-IL')}</div>
  </div>
  <div class="student-name">\u05E9\u05DD \u05D4\u05EA\u05DC\u05DE\u05D9\u05D3: ${studentName}</div>
  ${fieldsHTML}
</body>
</html>`;

    const w = window.open('', '_blank', 'width=800,height=900');
    if (w) {
      w.document.write(printHTML);
      w.document.close();
      setTimeout(() => w.print(), 500);
    }
  },

  _talaExportAll() {
    const _gc = (s) => (typeof DATA_CACHE !== 'undefined' && DATA_CACHE[s]) ? DATA_CACHE[s] : [];
    let students = _gc('\u05EA\u05DC\u05DE\u05D9\u05D3\u05D9\u05DD');
    if (!students.length) students = Pages._studentsDemoData ? Pages._studentsDemoData() : [];

    const allIds = students.map((s, i) => String(Utils.rowId(s) || s._row || i))
      .filter(sId => localStorage.getItem('bht_tala_' + sId));

    if (!allIds.length) {
      if (typeof Utils !== 'undefined' && Utils.toast) Utils.toast('\u05D0\u05D9\u05DF \u05EA\u05DC"\u05D0\u05D5\u05EA \u05DC\u05D4\u05D3\u05E4\u05E1\u05D4', 'warning');
      return;
    }

    allIds.forEach((sId, idx) => {
      setTimeout(() => Pages._talaPrint(sId), idx * 600);
    });
  },

  /* ---- Pre-fill from DOCX data (import helper) ---- */
  _talaImportData: [
    { name: '\u05D9\u05D0\u05D9\u05E8 \u05D0\u05DC\u05E2\u05D6\u05E8', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05DE\u05E0\u05EA \u05DE\u05E9\u05DB\u05DC \u05D2\u05D1\u05D5\u05DC\u05D9\u05EA - 79. \u05E7\u05D5\u05E9\u05D9 \u05E8\u05D1 \u05D1\u05E9\u05E4\u05D4 \u05D5\u05D4\u05DE\u05E9\u05D2\u05D4, \u05E7\u05D5\u05E9\u05D9 \u05D1\u05D7\u05E9\u05D9\u05D1\u05D4, \u05D6\u05DB\u05E8\u05D5\u05DF, \u05D4\u05D1\u05E0\u05D4 \u05D5\u05E2\u05D9\u05D1\u05D5\u05D3 \u05DE\u05D9\u05D3\u05E2, \u05E7\u05E9\u05D9\u05D9\u05DD \u05D2\u05E8\u05E4\u05D5\u05DE\u05D5\u05D8\u05D5\u05E8\u05D9\u05D9\u05DD \u05D5\u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1 \u05E8\u05D1\u05D5\u05EA. \u05E7\u05D5\u05E9\u05D9 \u05D1\u05E7\u05E9\u05D1, \u05DC\u05D0 \u05DE\u05D8\u05D5\u05E4\u05DC \u05D1\u05E2\u05E7\u05D1\u05D5\u05EA \u05D8\u05D9\u05E7\u05D9\u05DD. (\u05D0\u05D1\u05D7\u05D5\u05DF \u05E4\u05E1\u05D9\u05DB\u05D5\u05D3\u05D9\u05D3\u05E7\u05D8\u05D9, 2/25)', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05DE\u05DE\u05D5\u05E9\u05DE\u05E2, \u05E8\u05D2\u05D9\u05E9 \u05D5\u05E7\u05E9\u05D5\u05D1 \u05DC\u05D7\u05D1\u05E8\u05D9\u05DD. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05D2\u05D1\u05D5\u05D4\u05D4 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4, \u05E2\u05E7\u05D1\u05D9\u05D5\u05EA \u05D5\u05E9\u05DE\u05D9\u05E8\u05D4 \u05E2\u05DC \u05D6\u05DE\u05E0\u05D9\u05DD', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05E7\u05E8\u05D9\u05D0\u05D4 - \u05E7\u05E8\u05D9\u05D0\u05D4 \u05D0\u05D9\u05D8\u05D9\u05EA \u05D5\u05DC\u05D0 \u05DE\u05D3\u05D5\u05D9\u05E7\u05EA. \u05DB\u05EA\u05D9\u05D1\u05D4 - \u05E7\u05E9\u05D9\u05D9\u05DD \u05D2\u05E8\u05E4\u05D5\u05DE\u05D5\u05D8\u05D5\u05E8\u05D9\u05D9\u05DD, \u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1 \u05E8\u05D1\u05D5\u05EA, \u05D7\u05E1\u05E8 \u05D1\u05E2\u05D9\u05E6\u05D5\u05E8\u05D9\u05DD, \u05EA\u05D7\u05D1\u05D9\u05E8 \u05DC\u05E7\u05D5\u05D9. \u05D4\u05D1\u05E0\u05D4 \u05D1\u05D2\u05DE\u05E8\u05D0 - \u05E7\u05E9\u05D9\u05D9\u05DD \u05D1\u05D4\u05D1\u05E0\u05D4, \u05D7\u05E9\u05D9\u05D1\u05D4 \u05D5\u05D4\u05E1\u05E7\u05EA \u05DE\u05E1\u05E7\u05E0\u05D5\u05EA', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05E7\u05E9\u05D1\u05D4 \u05D1\u05E9\u05D9\u05E2\u05D5\u05E8\u05D9\u05DD, \u05DC\u05DE\u05D9\u05D3\u05D4 \u05E4\u05E2\u05D9\u05DC\u05D4 \u05D9\u05D5\u05EA\u05E8 \u05E2\u05DD \u05D4\u05E9\u05EA\u05EA\u05E4\u05D5\u05EA \u05D1\u05E9\u05D9\u05E2\u05D5\u05E8', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05DE\u05D5\u05D3\u05E2\u05D5\u05EA \u05D5\u05E9\u05D9\u05DE\u05EA \u05DC\u05D1 \u05DC\u05E1\u05D9\u05D8\u05D5\u05D0\u05E6\u05D9\u05D5\u05EA \u05D1\u05D4\u05DD \u05E0\u05D3\u05E8\u05E9 \u05DC\u05D4\u05D9\u05D5\u05EA \u05E7\u05E9\u05D5\u05D1 \u05D5\u05E9\u05E7\u05D8', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05DE\u05DE\u05D5\u05E9\u05DE\u05E2, \u05E8\u05D2\u05D9\u05E9 \u05D5\u05E7\u05E9\u05D5\u05D1 \u05DC\u05D7\u05D1\u05E8\u05D9\u05DD', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05DE\u05D5\u05D3\u05E2\u05D5\u05EA \u05D5\u05E9\u05D9\u05DE\u05EA \u05DC\u05D1 \u05DC\u05E1\u05D9\u05D8\u05D5\u05D0\u05E6\u05D9\u05D5\u05EA \u05D1\u05D4\u05DD \u05E0\u05D3\u05E8\u05E9 \u05DC\u05D4\u05D9\u05D5\u05EA \u05E7\u05E9\u05D5\u05D1 \u05D5\u05E9\u05E7\u05D8', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':'\u05D9\u05D0\u05D9\u05E8 \u05D0\u05DC\u05E2\u05D6\u05E8'} },
    { name: '\u05D4\u05DC\u05DC \u05DB\u05E5', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05EA\u05E4\u05E7\u05D5\u05D3 \u05D0\u05D9\u05E0\u05D8\u05DC\u05E7\u05D8\u05D5\u05D0\u05DC\u05D9 \u05DE\u05DE\u05D5\u05E6\u05E2 (IQ 92) \u05DC\u05DC\u05D0 \u05E4\u05E2\u05E8\u05D9\u05DD \u05D1\u05D5\u05DC\u05D8\u05D9\u05DD. \u05E7\u05E9\u05D9\u05D9\u05DD \u05D1\u05D5\u05DC\u05D8\u05D9\u05DD \u05D1\u05D6\u05DB\u05E8\u05D5\u05DF \u05D7\u05D6\u05D5\u05EA\u05D9 \u05D5\u05E9\u05DE\u05D9\u05E2\u05EA\u05D9 \u05D5\u05DB\u05DF \u05D1\u05D6\u05DB\u05E8\u05D5\u05DF \u05E2\u05D1\u05D5\u05D3\u05D4. \u05E7\u05E9\u05D9\u05D9\u05DD \u05D2\u05E8\u05E4\u05D5\u05DE\u05D5\u05D8\u05D5\u05E8\u05D9\u05D9\u05DD \u05DE\u05E9\u05DE\u05E2\u05D5\u05EA\u05D9\u05D9\u05DD. \u05E7\u05D5\u05E9\u05D9 \u05D1\u05E7\u05E9\u05D1 - \u05DC\u05D0 \u05DE\u05D8\u05D5\u05E4\u05DC \u05E2\u05E7\u05D1 \u05EA\u05D5\u05E4\u05E2\u05D5\u05EA \u05DC\u05D5\u05D5\u05D0\u05D9. (\u05D0\u05D1\u05D7\u05D5\u05DF \u05E4\u05E1\u05D9\u05DB\u05D5\u05D3\u05D9\u05D3\u05E7\u05D8\u05D9, 3/25)', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05E7\u05E8\u05D9\u05D0\u05D4 - \u05E7\u05E6\u05D1 \u05EA\u05E7\u05D9\u05DF \u05DC\u05D2\u05D9\u05DC. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05D2\u05D1\u05D5\u05D4\u05D4 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05DB\u05D5\u05E9\u05E8 \u05D0\u05E8\u05D2\u05D5\u05DF \u05D8\u05D5\u05D1, \u05DE\u05D5\u05D3\u05E2\u05D5\u05EA \u05E2\u05E6\u05DE\u05D9\u05EA \u05DC\u05E7\u05E9\u05D9\u05D9\u05DD \u05D5\u05D9\u05DB\u05D5\u05DC\u05D5\u05EA', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05E7\u05E8\u05D9\u05D0\u05D4 - \u05E7\u05E8\u05D9\u05D0\u05D4 \u05DC\u05D0 \u05DE\u05D3\u05D5\u05D9\u05E7\u05EA. \u05DB\u05EA\u05D9\u05D1\u05D4 - \u05E7\u05E9\u05D9\u05D9\u05DD \u05D2\u05E8\u05E4\u05D5\u05DE\u05D5\u05D8\u05D5\u05E8\u05D9\u05D9\u05DD, \u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1 \u05E8\u05D1\u05D5\u05EA \u05D5\u05D4\u05D7\u05DC\u05E4\u05EA \u05E2\u05D9\u05E6\u05D5\u05E8\u05D9\u05DD. \u05D4\u05D1\u05E0\u05D4 \u05D1\u05D2\u05DE\u05E8\u05D0 - \u05E7\u05E9\u05D9\u05D9\u05DD \u05D1\u05D4\u05D1\u05E0\u05D4, \u05D7\u05E9\u05D9\u05D1\u05D4 \u05D5\u05D4\u05E1\u05E7\u05EA \u05DE\u05E1\u05E7\u05E0\u05D5\u05EA. \u05D1\u05E7\u05E8\u05D4 \u05E2\u05E6\u05DE\u05D9\u05EA \u05D5\u05D1\u05D3\u05D9\u05E7\u05EA \u05EA\u05D5\u05E6\u05E8\u05D9\u05DD', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05D1\u05E7\u05E8\u05D4 \u05E2\u05E6\u05DE\u05D9\u05EA \u05D5\u05D1\u05D3\u05D9\u05E7\u05EA \u05EA\u05D5\u05E6\u05E8\u05D9\u05DD', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05D4\u05DB\u05E8\u05D4 \u05D1\u05D2\u05D1\u05D5\u05DC\u05D5\u05EA \u05D5\u05E1\u05DE\u05DB\u05D5\u05EA. \u05E4\u05E0\u05D9\u05D4 \u05D1\u05DB\u05D1\u05D5\u05D3 \u05DC\u05D7\u05D1\u05E8\u05D9\u05DD \u05D5\u05E7\u05D1\u05DC\u05EA \u05D4\u05D0\u05D7\u05E8', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05D4\u05D5\u05E8\u05D0\u05D4 \u05DE\u05EA\u05E7\u05E0\u05EA \u05D1\u05E7\u05E8\u05D9\u05D0\u05D4 \u05D5\u05DB\u05EA\u05D9\u05D1\u05D4', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05D4\u05DB\u05E8\u05D4 \u05D1\u05D2\u05D1\u05D5\u05DC\u05D5\u05EA \u05D5\u05E1\u05DE\u05DB\u05D5\u05EA. \u05E4\u05E0\u05D9\u05D4 \u05D1\u05DB\u05D1\u05D5\u05D3 \u05DC\u05D7\u05D1\u05E8\u05D9\u05DD \u05D5\u05E7\u05D1\u05DC\u05EA \u05D4\u05D0\u05D7\u05E8', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05E9\u05DC\u05DE\u05D4 \u05DC\u05D9\u05D9\u05D1\u05DC\u05E8', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05EA\u05E4\u05E7\u05D5\u05D3 \u05D0\u05D9\u05E0\u05D8\u05DC\u05E7\u05D8\u05D5\u05D0\u05DC\u05D9 \u05DE\u05DE\u05D5\u05E6\u05E2 \u05E0\u05DE\u05D5\u05DA (IQ 86) \u05DE\u05D0\u05D5\u05D1\u05D7\u05DF \u05E2\u05DD \u05D1\u05E2\u05D9\u05D9\u05EA \u05E7\u05E9\u05D1 \u05D5\u05E8\u05D9\u05DB\u05D5\u05D6 ADHD, \u05E7\u05D5\u05E9\u05D9 \u05E8\u05D2\u05E9\u05D9 \u05D5\u05D7\u05D5\u05E1\u05E8 \u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9 \u05D1\u05E0\u05D5\u05D2\u05E2 \u05DC\u05D9\u05DB\u05D5\u05DC\u05EA \u05E9\u05DC\u05D5, \u05E7\u05D5\u05E9\u05D9 \u05D1\u05E7\u05D1\u05DC\u05EA \u05E1\u05DE\u05DB\u05D5\u05EA \u05D5\u05D2\u05D1\u05D5\u05DC\u05D5\u05EA.', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05E7\u05E8\u05D9\u05D0\u05D4 - \u05E7\u05E6\u05D1 \u05EA\u05E7\u05D9\u05DF \u05DC\u05D2\u05D9\u05DC. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05D7\u05DC\u05E7\u05D9\u05EA \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05D9\u05DB\u05D5\u05DC\u05EA \u05D7\u05D1\u05E8\u05EA\u05D9\u05EA \u05D8\u05D5\u05D1\u05D4', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05DB\u05EA\u05D9\u05D1\u05D4 - \u05E9\u05D9\u05E4\u05D5\u05E8 \u05E9\u05D9\u05D1\u05D5\u05E9\u05D9 \u05D0\u05D9\u05D5\u05EA \u05D5\u05E2\u05D9\u05E6\u05D5\u05D1 \u05D0\u05D5\u05EA\u05D9\u05D5\u05EA \u05DC\u05E8\u05DE\u05D4 \u05EA\u05E7\u05D9\u05E0\u05D4 \u05D5\u05E7\u05E6\u05D1 \u05EA\u05E7\u05D9\u05DF. \u05D4\u05E2\u05DC\u05D0\u05EA \u05D4\u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D3\u05D9\u05DE\u05D5\u05D9 \u05E2\u05E6\u05DE\u05D9, \u05D4\u05DB\u05E8\u05D4 \u05D1\u05D2\u05D1\u05D5\u05DC\u05D5\u05EA \u05D5\u05E1\u05DE\u05DB\u05D5\u05EA', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05E9\u05D9\u05E4\u05D5\u05E8 \u05E9\u05D9\u05D1\u05D5\u05E9\u05D9 \u05D0\u05D9\u05D5\u05EA \u05D5\u05E2\u05D9\u05E6\u05D5\u05D1 \u05D0\u05D5\u05EA\u05D9\u05D5\u05EA', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D3\u05D9\u05DE\u05D5\u05D9 \u05E2\u05E6\u05DE\u05D9, \u05D4\u05DB\u05E8\u05D4 \u05D1\u05D2\u05D1\u05D5\u05DC\u05D5\u05EA \u05D5\u05E1\u05DE\u05DB\u05D5\u05EA', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05D4\u05D5\u05E8\u05D0\u05D4 \u05DE\u05EA\u05E7\u05E0\u05EA \u05D1\u05DB\u05EA\u05D9\u05D1\u05D4 \u05D5\u05D0\u05D9\u05D5\u05EA', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D3\u05D9\u05DE\u05D5\u05D9 \u05E2\u05E6\u05DE\u05D9, \u05D4\u05DB\u05E8\u05D4 \u05D1\u05D2\u05D1\u05D5\u05DC\u05D5\u05EA \u05D5\u05E1\u05DE\u05DB\u05D5\u05EA', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05E6\u05D1\u05D9 \u05E1\u05D9\u05D2\u05DC', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA \u05E2\u05DC \u05E8\u05E6\u05E3 \u05D4\u05D0\u05D5\u05D8\u05D9\u05D6\u05DD ASD. \u05D0\u05D9 \u05D4\u05D1\u05E0\u05EA \u05E7\u05D5\u05D3\u05D9\u05DD \u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD. \u05DC\u05D5\u05E7\u05D7 \u05EA\u05E8\u05D5\u05E4\u05D4 \u05E0\u05D2\u05D3 \u05D7\u05E8\u05D3\u05D5\u05EA \u05E1\u05E8\u05E0\u05D3\u05D4.', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05E7\u05E8\u05D9\u05D0\u05D4 \u05D5\u05D4\u05D1\u05E0\u05D4 \u05D1\u05E8\u05DE\u05D4 \u05EA\u05E7\u05D9\u05E0\u05D4, \u05D9\u05DB\u05D5\u05DC\u05EA \u05D0\u05D9\u05E0\u05D8\u05DC\u05E7\u05D8\u05D5\u05D0\u05DC\u05D9\u05EA \u05EA\u05E7\u05D9\u05E0\u05D4. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05D2\u05D1\u05D5\u05D4\u05D4 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05E8\u05D2\u05D9\u05E9 \u05DC\u05D6\u05D5\u05DC\u05EA, \u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05DB\u05EA\u05D9\u05D1\u05D4 - \u05E2\u05D1\u05D5\u05D3\u05D4 \u05E2\u05DC \u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1. \u05D4\u05D1\u05E0\u05D4 - \u05E4\u05D9\u05EA\u05D5\u05D7 \u05D5\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D9\u05DB\u05D5\u05DC\u05EA \u05D4\u05D1\u05E0\u05D4 \u05D5\u05D4\u05E1\u05E7\u05EA \u05DE\u05E1\u05E7\u05E0\u05D5\u05EA. \u05D0\u05D7\u05E8\u05D9\u05D5\u05EA \u05DC\u05D6\u05DE\u05E0\u05D9\u05DD \u05D5\u05E1\u05D3\u05E8 \u05D9\u05D5\u05DD', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05E2\u05D1\u05D5\u05D3\u05D4 \u05E2\u05DC \u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1 \u05D5\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05D1\u05E0\u05D4', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05DC\u05D9\u05DE\u05D5\u05D3 \u05E7\u05D5\u05D3\u05D9\u05DD \u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD \u05D5\u05EA\u05E7\u05E9\u05D5\u05E8\u05EA \u05E0\u05DB\u05D5\u05E0\u05D4 \u05E2\u05DD \u05D4\u05E6\u05D5\u05D5\u05EA \u05D5\u05D7\u05D1\u05E8\u05D9\u05D5', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05E8\u05D2\u05D9\u05E9 \u05DC\u05D6\u05D5\u05DC\u05EA, \u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05DC\u05D9\u05DE\u05D5\u05D3 \u05E7\u05D5\u05D3\u05D9\u05DD \u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD \u05D5\u05EA\u05E7\u05E9\u05D5\u05E8\u05EA \u05E0\u05DB\u05D5\u05E0\u05D4 \u05E2\u05DD \u05D4\u05E6\u05D5\u05D5\u05EA \u05D5\u05D7\u05D1\u05E8\u05D9\u05D5', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05DE\u05E0\u05D7\u05DD \u05E1\u05E0\u05D4\u05D3\u05E8\u05D0\u05D9', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05D1\u05E2\u05D9\u05D9\u05EA \u05E7\u05E9\u05D1 \u05D5\u05E8\u05D9\u05DB\u05D5\u05D6 ADHD. \u05E7\u05D5\u05E9\u05D9 \u05D7\u05D1\u05E8\u05EA\u05D9 \u05D5\u05E8\u05D2\u05E9\u05D9 - \u05E4\u05D2\u05D9\u05E2 \u05DE\u05D0\u05D5\u05D3. \u05E4\u05E2\u05E8 \u05DE\u05E9\u05DE\u05E2\u05D5\u05EA\u05D9 \u05D1\u05D9\u05DF \u05D4\u05E0\u05E8\u05D0\u05D5\u05EA \u05DC\u05D1\u05D2\u05E8\u05D5\u05EA \u05D1\u05E4\u05D5\u05E2\u05DC \u05D1\u05E2\u05E7\u05D1\u05D5\u05EA \u05D1\u05E2\u05D9\u05D4 \u05E8\u05E4\u05D5\u05D0\u05D9\u05EA. \u05E4\u05E2\u05E8 \u05DC\u05D9\u05DE\u05D5\u05D3\u05D9 \u05D2\u05D3\u05DC.', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05E7\u05E8\u05D9\u05D0\u05D4 - \u05E7\u05E6\u05D1 \u05EA\u05E7\u05D9\u05DF \u05DC\u05D2\u05D9\u05DC. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05E8\u05D2\u05D9\u05E9 \u05E9\u05DD \u05DC\u05D1 \u05DC\u05E4\u05E8\u05D8\u05D9\u05DD \u05D4\u05E7\u05D8\u05E0\u05D9\u05DD, \u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05D4\u05D1\u05E0\u05D4 \u05D1\u05D2\u05DE\u05E8\u05D0 - \u05D7\u05D9\u05D6\u05D5\u05E7\u05D9\u05DD \u05D1\u05D4\u05D1\u05E0\u05D4, \u05D7\u05E9\u05D9\u05D1\u05D4 \u05D5\u05D4\u05E1\u05E7\u05EA \u05DE\u05E1\u05E7\u05E0\u05D5\u05EA. \u05E2\u05D1\u05D5\u05D3\u05D4 \u05E4\u05E8\u05D8\u05E0\u05D9\u05EA \u05D1\u05D4\u05D5\u05E8\u05D0\u05EA \u05D4\u05D2\u05DE\u05E8\u05D0. \u05DB\u05EA\u05D9\u05D1\u05D4 - \u05E2\u05D1\u05D5\u05D3\u05D4 \u05E2\u05DC \u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05DE\u05E9\u05DE\u05E2\u05EA \u05D2\u05DD \u05DB\u05E9\u05DC\u05D0 \u05DE\u05E1\u05EA\u05D3\u05E8', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05D1\u05E0\u05D4 \u05D1\u05D2\u05DE\u05E8\u05D0, \u05E2\u05D1\u05D5\u05D3\u05D4 \u05E2\u05DC \u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05D4\u05D1\u05E0\u05EA \u05E1\u05D9\u05D8\u05D5\u05D0\u05E6\u05D9\u05D5\u05EA \u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA. \u05E4\u05D9\u05EA\u05D5\u05D7 \u05D7\u05D5\u05E1\u05DF \u05E4\u05E0\u05D9\u05DE\u05D9 \u05D5\u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05E8\u05D2\u05D9\u05E9 \u05E9\u05DD \u05DC\u05D1 \u05DC\u05E4\u05E8\u05D8\u05D9\u05DD \u05D4\u05E7\u05D8\u05E0\u05D9\u05DD, \u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05D4\u05DB\u05E8\u05D4 \u05D1\u05D2\u05D1\u05D5\u05DC\u05D5\u05EA \u05D5\u05E1\u05DE\u05DB\u05D5\u05EA. \u05D4\u05D1\u05E0\u05EA \u05E1\u05D9\u05D8\u05D5\u05D0\u05E6\u05D9\u05D5\u05EA \u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA. \u05E4\u05D9\u05EA\u05D5\u05D7 \u05D7\u05D5\u05E1\u05DF \u05E4\u05E0\u05D9\u05DE\u05D9 \u05D5\u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05D1\u05E6\u05DC\u05D0\u05DC \u05E4\u05D8\u05D9\u05E0\u05D5', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05EA\u05E4\u05E7\u05D5\u05D3 \u05D0\u05D9\u05E0\u05D8\u05DC\u05E7\u05D8\u05D5\u05D0\u05DC\u05D9 \u05DE\u05DE\u05D5\u05E6\u05E2 (IQ 96). \u05D4\u05E0\u05DE\u05DB\u05D4 \u05D1\u05D4\u05D1\u05E0\u05D4 \u05DE\u05D9\u05DC\u05D5\u05DC\u05D9\u05EA. \u05D0\u05D5\u05D1\u05D7\u05DF \u05E2\u05DD \u05D1\u05E2\u05D9\u05D9\u05EA \u05E7\u05E9\u05D1 \u05D5\u05E8\u05D9\u05DB\u05D5\u05D6 ADHD. \u05E7\u05D5\u05E9\u05D9 \u05E8\u05D2\u05E9\u05D9 \u05D5\u05D7\u05D1\u05E8\u05EA\u05D9 \u05DE\u05E9\u05DE\u05E2\u05D5\u05EA\u05D9. \u05E7\u05D5\u05E9\u05D9 \u05D1\u05E7\u05E8\u05D9\u05D0\u05D4 \u05D4\u05D1\u05E0\u05EA \u05D4\u05E0\u05E7\u05E8\u05D0 \u05D5\u05D4\u05D1\u05E2\u05D4 \u05D1\u05DB\u05EA\u05D1.', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05E8\u05D2\u05D9\u05E9 \u05D5\u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05E7\u05E8\u05D9\u05D0\u05D4 - \u05D7\u05D9\u05D6\u05D5\u05E7 \u05E9\u05D8\u05E3 \u05E7\u05E8\u05D9\u05D0\u05D4 \u05D5\u05D3\u05D9\u05D5\u05E7. \u05D4\u05D1\u05E0\u05EA \u05D4\u05E0\u05E7\u05E8\u05D0 - \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05D1\u05E0\u05EA \u05D4\u05E0\u05E7\u05E8\u05D0 \u05D3\u05E8\u05DA \u05D4\u05D5\u05E8\u05D0\u05D4 \u05DE\u05EA\u05E7\u05E0\u05EA. \u05DB\u05EA\u05D9\u05D1\u05D4 - \u05E9\u05D9\u05E4\u05D5\u05E8 \u05D4\u05D1\u05E2\u05D4 \u05D1\u05DB\u05EA\u05D1. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9, \u05D9\u05E6\u05D9\u05E8\u05EA \u05E7\u05E9\u05E8\u05D9\u05DD \u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD \u05D5\u05D4\u05D1\u05E0\u05EA \u05E7\u05D5\u05D3\u05D9\u05DD \u05D1\u05E6\u05D5\u05E8\u05D4 \u05EA\u05E7\u05D9\u05E0\u05D4', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05E9\u05D8\u05E3 \u05E7\u05E8\u05D9\u05D0\u05D4 \u05D5\u05D3\u05D9\u05D5\u05E7, \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05D1\u05E0\u05EA \u05D4\u05E0\u05E7\u05E8\u05D0, \u05E9\u05D9\u05E4\u05D5\u05E8 \u05D4\u05D1\u05E2\u05D4 \u05D1\u05DB\u05EA\u05D1', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9, \u05D9\u05E6\u05D9\u05E8\u05EA \u05E7\u05E9\u05E8\u05D9\u05DD \u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD \u05D5\u05D4\u05D1\u05E0\u05EA \u05E7\u05D5\u05D3\u05D9\u05DD \u05D1\u05E6\u05D5\u05E8\u05D4 \u05EA\u05E7\u05D9\u05E0\u05D4', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05D4\u05D5\u05E8\u05D0\u05D4 \u05DE\u05EA\u05E7\u05E0\u05EA \u05D1\u05E7\u05E8\u05D9\u05D0\u05D4, \u05D4\u05D1\u05E0\u05EA \u05D4\u05E0\u05E7\u05E8\u05D0 \u05D5\u05DB\u05EA\u05D9\u05D1\u05D4', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9, \u05D9\u05E6\u05D9\u05E8\u05EA \u05E7\u05E9\u05E8\u05D9\u05DD \u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD \u05D5\u05D4\u05D1\u05E0\u05EA \u05E7\u05D5\u05D3\u05D9\u05DD \u05D1\u05E6\u05D5\u05E8\u05D4 \u05EA\u05E7\u05D9\u05E0\u05D4', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05D3\u05D5\u05D1\u05D9 \u05E4\u05E8\u05D3\u05E1\u05D5\u05DF', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05E8\u05E7\u05E2 \u05E9\u05DC \u05E4\u05D2\u05D5\u05EA \u05DE\u05E9\u05DE\u05E2\u05D5\u05EA\u05D9\u05EA, \u05D0\u05D7\u05D3 \u05DE\u05E9\u05DC\u05D9\u05E9\u05D9\u05D4. \u05D9\u05DB\u05D5\u05DC\u05EA \u05D0\u05D9\u05E0\u05D8\u05DC\u05D5\u05E7\u05D8\u05D0\u05DC\u05D9\u05EA \u05EA\u05E7\u05D9\u05E0\u05D4 (IQ 95). \u05D0\u05D9\u05D8\u05D9\u05D5\u05EA \u05DB\u05DC\u05DC\u05D9\u05EA. \u05E7\u05D5\u05E9\u05D9 \u05E8\u05D2\u05E9\u05D9, \u05DE\u05D5\u05E4\u05E0\u05DE\u05D5\u05EA.', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05E7\u05E8\u05D9\u05D0\u05D4 - \u05E7\u05E6\u05D1 \u05EA\u05E7\u05D9\u05DF \u05DC\u05D2\u05D9\u05DC. \u05DB\u05EA\u05D9\u05D1\u05D4 - \u05E9\u05D9\u05E4\u05D5\u05E8 \u05D2\u05D3\u05D5\u05DC \u05D1\u05DB\u05EA\u05D9\u05D1 \u05D5\u05D1\u05DB\u05EA\u05D1 \u05D5\u05D1\u05EA\u05D7\u05D1\u05D9\u05E8. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05D2\u05D1\u05D5\u05D4\u05D4 \u05DE\u05D0\u05D5\u05D3 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05DE\u05DE\u05D5\u05E9\u05DE\u05E2, \u05D4\u05EA\u05E0\u05D4\u05D2\u05D5\u05EA \u05E2\u05D3\u05D9\u05E0\u05D4, \u05D7\u05D1\u05E8\u05D5\u05EA\u05D9, \u05E8\u05D2\u05D9\u05E9', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05E7\u05E8\u05D9\u05D0\u05D4 - \u05E9\u05D9\u05E4\u05D5\u05E8 \u05D4\u05D3\u05D9\u05D5\u05E7. \u05D4\u05D1\u05E0\u05D4 - \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05D1\u05E0\u05D4 \u05D5\u05D4\u05DB\u05E8\u05EA \u05D4\u05E9\u05E4\u05D4 \u05E9\u05DC \u05D4\u05D2\u05DE\u05E8\u05D0. \u05D4\u05D1\u05E0\u05EA \u05D4\u05E0\u05E7\u05E8\u05D0 - \u05D9\u05DB\u05D5\u05DC\u05EA \u05D4\u05D8\u05E8\u05DE\u05D4 \u05D5\u05E0\u05D9\u05D1\u05D5\u05D9, \u05D0\u05D9\u05EA\u05D5\u05E8 \u05E8\u05E2\u05D9\u05D5\u05DF \u05DE\u05E8\u05DB\u05D6\u05D9. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9, \u05DC\u05E0\u05E1\u05D5\u05EA \u05DC\u05D2\u05E8\u05D5\u05DD \u05DC\u05D5 \u05DC\u05D4\u05D9\u05E4\u05EA\u05D7 \u05D9\u05D5\u05EA\u05E8 \u05D5\u05DC\u05D3\u05D1\u05E8 \u05D9\u05D5\u05EA\u05E8', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05E9\u05D9\u05E4\u05D5\u05E8 \u05D4\u05D3\u05D9\u05D5\u05E7 \u05D1\u05E7\u05E8\u05D9\u05D0\u05D4, \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05D1\u05E0\u05D4 \u05D5\u05D4\u05DB\u05E8\u05EA \u05E9\u05E4\u05EA \u05D4\u05D2\u05DE\u05E8\u05D0', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9, \u05DC\u05E0\u05E1\u05D5\u05EA \u05DC\u05D2\u05E8\u05D5\u05DD \u05DC\u05D5 \u05DC\u05D4\u05D9\u05E4\u05EA\u05D7 \u05D9\u05D5\u05EA\u05E8 \u05D5\u05DC\u05D3\u05D1\u05E8 \u05D9\u05D5\u05EA\u05E8', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05DE\u05DE\u05D5\u05E9\u05DE\u05E2, \u05D4\u05EA\u05E0\u05D4\u05D2\u05D5\u05EA \u05E2\u05D3\u05D9\u05E0\u05D4, \u05D7\u05D1\u05E8\u05D5\u05EA\u05D9, \u05E8\u05D2\u05D9\u05E9', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D1\u05D9\u05D8\u05D7\u05D5\u05DF \u05E2\u05E6\u05DE\u05D9, \u05DC\u05E0\u05E1\u05D5\u05EA \u05DC\u05D2\u05E8\u05D5\u05DD \u05DC\u05D5 \u05DC\u05D4\u05D9\u05E4\u05EA\u05D7 \u05D9\u05D5\u05EA\u05E8 \u05D5\u05DC\u05D3\u05D1\u05E8 \u05D9\u05D5\u05EA\u05E8', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05D9\u05E2\u05E7\u05D1 \u05E8\u05D5\u05D6\u05DF', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05D4\u05E4\u05E8\u05E2\u05EA \u05EA\u05E7\u05E9\u05D5\u05E8\u05EA ASD. \u05E7\u05D5\u05E9\u05D9 \u05D1\u05D4\u05D1\u05E0\u05EA \u05E1\u05D9\u05D8\u05D5\u05D0\u05E6\u05D9\u05D5\u05EA. \u05E7\u05D5\u05E9\u05D9 \u05D1\u05D4\u05D1\u05E0\u05EA \u05D4\u05D9\u05E8\u05E8\u05DB\u05D9\u05D4. \u05E7\u05D5\u05E9\u05D9 \u05D7\u05D1\u05E8\u05EA\u05D9. \u05D1\u05E2\u05D9\u05D9\u05EA \u05E7\u05E9\u05D1 \u05D5\u05E8\u05D9\u05DB\u05D5\u05D6.', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05E7\u05E8\u05D9\u05D0\u05D4 \u05D5\u05DB\u05EA\u05D9\u05D1\u05D4 \u05D1\u05DE\u05E6\u05D1 \u05EA\u05E7\u05D9\u05DF, \u05D4\u05D1\u05E0\u05D4 \u05D8\u05D5\u05D1\u05D4 \u05E9\u05DC \u05D4\u05D7\u05D5\u05DE\u05E8 \u05D4\u05E0\u05DC\u05DE\u05D3. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05D2\u05D1\u05D5\u05D4\u05D4 \u05DE\u05D0\u05D5\u05D3 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8, \u05E1\u05E7\u05E8\u05DF \u05D5\u05E8\u05D5\u05E6\u05D4 \u05DC\u05D3\u05E2\u05EA', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05DB\u05E8\u05EA \u05DE\u05D1\u05E0\u05D4 \u05D4\u05D2\u05DE\u05E8\u05D0 \u05D5\u05D4\u05DB\u05E8\u05EA \u05E9\u05E4\u05EA \u05D4\u05D2\u05DE\u05E8\u05D0. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05DE\u05E9\u05DE\u05E2\u05EA \u05D5\u05E7\u05D1\u05DC\u05EA \u05E1\u05DE\u05DB\u05D5\u05EA', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05DB\u05E8\u05EA \u05DE\u05D1\u05E0\u05D4 \u05D4\u05D2\u05DE\u05E8\u05D0 \u05D5\u05D4\u05DB\u05E8\u05EA \u05E9\u05E4\u05EA \u05D4\u05D2\u05DE\u05E8\u05D0', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05DC\u05DC\u05DE\u05D3 \u05D0\u05D5\u05EA\u05D5 \u05DC\u05E4\u05E8\u05E9 \u05E0\u05DB\u05D5\u05DF \u05D0\u05EA \u05D4\u05E1\u05D1\u05D9\u05D1\u05D4 \u05D5\u05D0\u05EA \u05D4\u05D7\u05D1\u05E8\u05D9\u05DD. \u05DC\u05DC\u05DE\u05D3 \u05D0\u05D5\u05EA\u05D5 \u05D0\u05EA \u05D4\u05D4\u05D9\u05E8\u05E8\u05DB\u05D9\u05D4 \u05D1\u05DE\u05DB\u05D9\u05E0\u05D4', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8, \u05E1\u05E7\u05E8\u05DF \u05D5\u05E8\u05D5\u05E6\u05D4 \u05DC\u05D3\u05E2\u05EA', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05DC\u05DC\u05DE\u05D3 \u05D0\u05D5\u05EA\u05D5 \u05DC\u05E4\u05E8\u05E9 \u05E0\u05DB\u05D5\u05DF \u05D0\u05EA \u05D4\u05E1\u05D1\u05D9\u05D1\u05D4 \u05D5\u05D0\u05EA \u05D4\u05D7\u05D1\u05E8\u05D9\u05DD. \u05DC\u05DC\u05DE\u05D3 \u05D0\u05D5\u05EA\u05D5 \u05D0\u05EA \u05D4\u05D4\u05D9\u05E8\u05E8\u05DB\u05D9\u05D4 \u05D1\u05DE\u05DB\u05D9\u05E0\u05D4', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05D9\u05E2\u05E7\u05D1 \u05E8\u05D5\u05D6\u05DF', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05E7\u05E9\u05D9\u05D9 \u05EA\u05E7\u05E9\u05D5\u05E8\u05EA - ASD, \u05E8\u05DE\u05D4 \u05D0\u05D9\u05E0\u05D8\u05DC\u05E7\u05D8\u05D5\u05D0\u05DC\u05D9\u05EA \u05D2\u05D1\u05D5\u05DC\u05D9\u05EA (IQ 72). \u05D7\u05E8\u05D3\u05D4 \u05D7\u05D1\u05E8\u05EA\u05D9\u05EA \u05D2\u05D1\u05D5\u05D4\u05D4 - \u05D0\u05D9\u05DC\u05DE\u05D5\u05EA \u05E1\u05DC\u05E7\u05D8\u05D9\u05D1\u05D9\u05EA.', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05DE\u05D5\u05DB\u05E9\u05E8 \u05D5\u05DE\u05D1\u05D9\u05DF \u05D8\u05D5\u05D1 \u05D0\u05EA \u05D4\u05D7\u05D5\u05DE\u05E8 \u05D4\u05E0\u05DC\u05DE\u05D3. \u05DE\u05D2\u05DC\u05D4 \u05E2\u05E0\u05D9\u05D9\u05DF \u05D1\u05DC\u05DE\u05D9\u05D3\u05D4 \u05D5\u05E0\u05D4\u05E0\u05D4 \u05DE\u05DC\u05DE\u05D9\u05D3\u05D4. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05D2\u05D1\u05D5\u05D4\u05D4 \u05DE\u05D0\u05D5\u05D3 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8, \u05E9\u05E7\u05D8 \u05D5\u05E2\u05D3\u05D9\u05DF', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05DB\u05EA\u05D9\u05D1\u05D4 - \u05E2\u05D1\u05D5\u05D3\u05D4 \u05E2\u05DC \u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05D3\u05D9\u05DE\u05D5\u05D9 \u05E2\u05E6\u05DE\u05D9 \u05D5\u05EA\u05D3\u05DE\u05D9\u05EA \u05D7\u05D9\u05D5\u05D1\u05D9\u05EA \u05E2\u05DC \u05E2\u05E6\u05DE\u05D5. \u05D3\u05E8\u05D1\u05D5\u05DF \u05D3\u05D9\u05D1\u05D5\u05E8 \u05E2\u05DD \u05D7\u05D1\u05E8\u05D9\u05DD \u05D5\u05D4\u05E6\u05D5\u05D5\u05EA \u05D5\u05E4\u05EA\u05D9\u05D7\u05D5\u05EA \u05DB\u05DC\u05DC\u05D9\u05EA', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05E2\u05D1\u05D5\u05D3\u05D4 \u05E2\u05DC \u05E9\u05D2\u05D9\u05D0\u05D5\u05EA \u05DB\u05EA\u05D9\u05D1', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D3\u05D9\u05DE\u05D5\u05D9 \u05E2\u05E6\u05DE\u05D9 \u05D5\u05EA\u05D3\u05DE\u05D9\u05EA \u05D7\u05D9\u05D5\u05D1\u05D9\u05EA. \u05D3\u05E8\u05D1\u05D5\u05DF \u05D3\u05D9\u05D1\u05D5\u05E8 \u05E2\u05DD \u05D7\u05D1\u05E8\u05D9\u05DD \u05D5\u05D4\u05E6\u05D5\u05D5\u05EA \u05D5\u05E4\u05EA\u05D9\u05D7\u05D5\u05EA \u05DB\u05DC\u05DC\u05D9\u05EA', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8, \u05E9\u05E7\u05D8 \u05D5\u05E2\u05D3\u05D9\u05DF', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D3\u05D9\u05DE\u05D5\u05D9 \u05E2\u05E6\u05DE\u05D9 \u05D5\u05EA\u05D3\u05DE\u05D9\u05EA \u05D7\u05D9\u05D5\u05D1\u05D9\u05EA. \u05D3\u05E8\u05D1\u05D5\u05DF \u05D3\u05D9\u05D1\u05D5\u05E8 \u05E2\u05DD \u05D7\u05D1\u05E8\u05D9\u05DD \u05D5\u05D4\u05E6\u05D5\u05D5\u05EA \u05D5\u05E4\u05EA\u05D9\u05D7\u05D5\u05EA \u05DB\u05DC\u05DC\u05D9\u05EA', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05D9\u05E9\u05E2\u05D9\u05D4\u05D5 \u05E9\u05D5\u05DC\u05D1\u05D9\u05E5', data: {'\u05E8\u05E7\u05E2_\u05DE\u05D5\u05D2\u05D1\u05DC\u05D5\u05EA':'\u05E7\u05E9\u05D9\u05D9\u05DD \u05D1\u05E7\u05E9\u05D1, ADHD, \u05DC\u05E7\u05D5\u05EA \u05DC\u05DE\u05D9\u05D3\u05D4 \u05D5\u05E7\u05E9\u05D9\u05D9\u05DD \u05E8\u05D2\u05E9\u05D9\u05D9\u05DD. \u05D0\u05DC\u05E8\u05D2\u05D9\u05D4', '\u05EA\u05D7\u05D5\u05DE\u05D9_\u05DB\u05D5\u05D7':'\u05DE\u05D1\u05D9\u05DF \u05D0\u05EA \u05D4\u05D7\u05D5\u05DE\u05E8 \u05D4\u05E0\u05DC\u05DE\u05D3. \u05DE\u05D2\u05DC\u05D4 \u05E2\u05E0\u05D9\u05D9\u05DF \u05D1\u05DC\u05DE\u05D9\u05D3\u05D4 \u05D5\u05E0\u05D4\u05E0\u05D4 \u05DE\u05DC\u05DE\u05D9\u05D3\u05D4. \u05E7\u05D9\u05D9\u05DE\u05EA \u05DE\u05D5\u05D8\u05D9\u05D1\u05E6\u05D9\u05D4 \u05D2\u05D1\u05D5\u05D4\u05D4 \u05DE\u05D0\u05D5\u05D3 \u05DC\u05DC\u05DE\u05D9\u05D3\u05D4. \u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8, \u05E8\u05D2\u05D9\u05E9', '\u05EA\u05D7\u05D5\u05DE\u05D9\u05DD_\u05DC\u05D7\u05D9\u05D6\u05D5\u05E7':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05DB\u05E8\u05EA \u05DE\u05D1\u05E0\u05D4 \u05D4\u05D2\u05DE\u05E8\u05D0 \u05D5\u05D4\u05DB\u05E8\u05EA \u05E9\u05E4\u05EA \u05D4\u05D2\u05DE\u05E8\u05D0. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05DE\u05E9\u05DE\u05E2\u05EA \u05D5\u05E7\u05D1\u05DC\u05EA \u05E1\u05DE\u05DB\u05D5\u05EA. \u05D4\u05D1\u05E0\u05EA \u05D4\u05D9\u05E8\u05E8\u05DB\u05D9\u05D4. \u05D7\u05D9\u05D6\u05D5\u05E7 \u05DE\u05D5\u05D3\u05E2\u05D5\u05EA \u05DE\u05D5\u05DC \u05D4\u05E6\u05D5\u05D5\u05EA', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D4\u05DB\u05E8\u05EA \u05DE\u05D1\u05E0\u05D4 \u05D4\u05D2\u05DE\u05E8\u05D0 \u05D5\u05D4\u05DB\u05E8\u05EA \u05E9\u05E4\u05EA \u05D4\u05D2\u05DE\u05E8\u05D0', '\u05D9\u05E2\u05D3\u05D9\u05DD_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D9\u05DD':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D3\u05D9\u05DE\u05D5\u05D9 \u05E2\u05E6\u05DE\u05D9 \u05D5\u05EA\u05D3\u05DE\u05D9\u05EA \u05D7\u05D9\u05D5\u05D1\u05D9\u05EA \u05E2\u05DC \u05E2\u05E6\u05DE\u05D5', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05DC\u05D9\u05DE\u05D5\u05D3\u05D9\u05D5\u05EA':'\u05D0\u05D5\u05D4\u05D1 \u05DC\u05E2\u05D6\u05D5\u05E8, \u05E8\u05D2\u05D9\u05E9', '\u05D0\u05E1\u05D8\u05E8\u05D8\u05D2\u05D9\u05D5\u05EA_\u05D7\u05D1\u05E8\u05EA\u05D9\u05D5\u05EA':'\u05D7\u05D9\u05D6\u05D5\u05E7 \u05D3\u05D9\u05DE\u05D5\u05D9 \u05E2\u05E6\u05DE\u05D9 \u05D5\u05EA\u05D3\u05DE\u05D9\u05EA \u05D7\u05D9\u05D5\u05D1\u05D9\u05EA \u05E2\u05DC \u05E2\u05E6\u05DE\u05D5', '\u05E9\u05DD_\u05DE\u05D5\u05E8\u05D4_\u05D4\u05EA\u05DC\u05D0':''} },
    { name: '\u05D0\u05D4\u05E8\u05D5\u05DF \u05E9\u05D8\u05D3\u05DC\u05E8', data: {} }
  ],

  /* Import pre-filled data for matching students */
  _talaImportFromDocx() {
    const _gc = (s) => (typeof DATA_CACHE !== 'undefined' && DATA_CACHE[s]) ? DATA_CACHE[s] : [];
    let students = _gc('\u05EA\u05DC\u05DE\u05D9\u05D3\u05D9\u05DD');
    if (!students.length) students = Pages._studentsDemoData ? Pages._studentsDemoData() : [];

    let imported = 0;
    Pages._talaImportData.forEach(imp => {
      if (!imp.data || !Object.keys(imp.data).length) return;
      // Find matching student by name
      const match = students.find(s => {
        const fullName = Utils.fullName(s);
        return fullName === imp.name || fullName.includes(imp.name) || imp.name.includes(fullName);
      });
      if (match) {
        const sId = String(Utils.rowId(match) || match._row || '');
        if (!sId) return;
        const key = 'bht_tala_' + sId;
        // Only import if no existing data
        if (!localStorage.getItem(key)) {
          const data = Object.assign({}, imp.data);
          data._lastUpdate = new Date().toLocaleDateString('he-IL');
          data._studentName = imp.name;
          localStorage.setItem(key, JSON.stringify(data));
          imported++;
        }
      }
    });
    return imported;
  }
});
